scwin.onpageload = function () {
  scwin.userClsCd = scwin.memJson.userClsCd;
  scwin.userId = scwin.memJson.userId;
  scwin.userNm = scwin.memJson.userNm;
  //사용자구분코드(01:그룹사구분코드(01:그룹사, 02:협력업체(운송), 03:선사, 04:화주, 05:자가운송업체, 06:렌터카(고객), 07:정비(고객))

  scwin.params = arrParent = $p.getAllParameter().paramData;
  scwin.params = scwin.params.argParams;
  if (!$c.gus.cfIsNull($p, scwin.params)) {
    scwin.argParams = scwin.params.split("^");
    scwin.shpCo = scwin.argParams[0];
    scwin.shpCoNm = scwin.argParams[1];
    scwin.lineCd = scwin.argParams[2];
    scwin.cyCd = scwin.argParams[3];
    scwin.cyNm = scwin.argParams[4];
    scwin.cntrTypCd = scwin.argParams[5];
    scwin.clsCd = scwin.argParams[6];
  }
};

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.f_OnLoad = async function () {
  gr_ContainerYardEachStockPresentConditionInformation.setRowStatusVisible(false);
  if (scwin.userClsCd != "01") {
    //사용자가 협력업체 일때
    ed_shpCo.setValue(scwin.memJson.clntNo);
    ed_shpNm.setValue(scwin.memJson.clntNm);
    ed_shpCo.setReadOnly(true);
    $c.gus.cfDisableObjects($p, [ed_shpNm, btn_shpCo]);
    await scwin.f_setLine();
    tbx_mchtCdTitle1.setValue("");
    udc_mchtCd.hide();
    udc_wrkPlCd.mandatoryCode = false;
    if (scwin.userId == "namdo11" || scwin.userId == "dygamman" || scwin.userId == "VANFIX") {
      udc_wrkPlCd.mandatoryCode = true;
    }
  } else {
    tbx_mchtCdTitle1.setValue("화주");
    udc_mchtCd.show();
    udc_wrkPlCd.mandatoryCode = true;
    await scwin.f_setLine();
  }
  scwin.f_defaultValue1(); // Grid LookUp - 수출입구분
  scwin.f_defaultValue3(); // Grid LookUp - LINE
  scwin.f_defaultValue5(); // Grid LookUp - 작업장

  if (scwin.argParams != "") {
    await scwin.f_settingParam();
    scwin.f_Retrieve();
  }
  ed_wrkPlCd.focus();
  $c.gus.cfDisableObjects($p, [btn_save]);
};
scwin.onUdcCompleted = function () {
  console.log('scwin.onUdcCompleted~~~');
  scwin.f_OnLoad();

  //공통코드 적용
  const codeOptions = [{
    grpCd: "SD133",
    compID: "gr_ContainerYardEachStockPresentConditionInformation:offRtrnClsCd"
  } //OFF;반납
  ];
  $c.data.setCommonCode($p, codeOptions);
  scwin.initComp();
};
scwin.initComp = function () {
  var codeObj = [ed_shpCo, ed_wrkPlCd, ed_mchtCd, ed_cvssl];
  for (var i = 0; i < codeObj.length; i++) {
    codeObj[i].unbind('onkeyup');
    codeObj[i].bind('onkeyup', scwin.upperCase);
  }
};
scwin.f_settingParam = async function () {
  ed_shpCo.setValue(scwin.shpCo);
  ed_shpNm.setValue(scwin.shpCoNm);

  //acb_lineCd.index = acb_lineCd.IndexOfColumn("code", lineCd);
  ed_wrkPlCd.setValue(scwin.cyCd);
  ed_wrkPlNm.setValue(scwin.cyNm);
  acb_typ.setValue(scwin.cntrTypCd);
  ds_condition.set("clsCd", scwin.clsCd);
  await scwin.f_setLine();
};

