// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  //if(scwin.userClsCd == "01"||"<%=loginDTO.getUserId()%>" == "namdo11"||"<%=loginDTO.getUserId()%>" == "dygamman"||"<%=loginDTO.getUserId()%>" == "VANFIX"){
  if (scwin.userClsCd == "01" || scwin.userId == "namdo11" || scwin.userId == "dygamman" || scwin.userId == "VANFIX") {
    //if (!await $c.gus.cfValidate([ed_wrkPlCd])) {	// 필수조건 : CY

    if (ed_wrkPlCd.getValue().trim() == '') {
      await $c.win.alert($p, 'CY은(는)  필수 입력 항목입니다.');
      return;
    }
  }
  ds_retrieve.setJSON([]);
  $c.sbm.execute($p, sbm_retrieve);
};

//-------------------------------------------------------------------------
// scwin.name : f_manifestListRegistMBL
// scwin.desc : 적하목록 Master BL 생성
//-------------------------------------------------------------------------
scwin.f_save = async function () {
  if (!(await $c.gus.cfValidate($p, [ed_wrkPlCd]))) {
    // 필수조건 : CY
    return;
  }
  if (ed_wrkPlCd.getValue() == "6C01") {
    //as-is 서비스 없음. /ds.op.wrkrslts.stockrslts.SavePectStockLocationCMD.do
    //$c.sbm.execute(sbm_regist);

    await $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다
    scwin.f_Retrieve();
  } else {
    await $c.win.alert($p, "PECTCY만 재고정보를 저장할수 있습니다.");
  }
};

