// OZ 리포트  발행
//-------------------------------------------------------------------------
scwin.f_OzReport = async function () {
  if (!(await $c.gus.cfValidate($p, [ed_wrkPlCd]))) {
    // 필수조건 : CY
    return;
  }
  let data = {
    oodiName: "op_303_03_03r",
    reportName: "/ds/op/wrkrslts/stockrslts/op_303_03_03r.ozr",
    odiParam: {
      cy: ed_wrkPlCd.getValue().trim(),
      shpCo: ed_shpCo.getValue().trim(),
      line: acb_lineCd.getValue(),
      fullEmptyClsCd: acb_fullEmptyClsCd.getValue().trim(),
      expimpCls: acb_con_expimpDomesticCls.getValue().trim(),
      cntrSizCd: acb_siz.getValue().trim(),
      cntrTypCd: acb_typ.getValue().trim(),
      arvIntendYn: acb_arvIntendYn.getValue(),
      socYn: acb_socYn.getValue().trim(),
      cvssl: ed_cvssl.getValue().trim(),
      portcnt: acb_con_portcnt.getValue().trim(),
      arrowDd: ed_arrowDd.getValue().trim()
    },
    viewerParam: {
      //useprogressbar : true, // 프로그레스바 쓸지 말지
      //zoom : 90, // 배율 설정
      //mode : printMode,
    },
    formParam: {}
  };

  //둘다선택 : 미리보기, 미리보기만 선택 :미리보기, 다 선택안함?, 인쇄만선택?
  let printMode = cbx_printCheck.getValue() == "1" ? true : false;
  let previewMode = cbx_previewCheck.getValue() == "1" ? true : false;
  if (previewMode) {
    let opts = {
      type: 'viewer',
      printMode: 'silent'
    };
    $c.ext.openOzReport($p, data, opts);
  } else if (printMode) {
    let opts = {
      type: 'print',
      printMode: 'view'
    };
    $c.ext.printOzReport($p, data, opts);
  } else {
    let opts = {
      type: 'print'
    };
    $c.ext.printOzReport($p, data, opts);
  }
};

