//-------------------------------------------------------------------------
// 팝업 전처리
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (type, disGubun, codeObj, nameObj) {
  var codeVal = codeObj ? codeObj.getValue().trim() : "";
  var nameVal = nameObj ? nameObj.getValue().trim() : "";
  if (codeObj) codeObj.setValue("");
  if (nameObj) nameObj.setValue("");
  if (type == "CODE") {
    if (codeVal == "") {
      if (disGubun == 2) {
        scwin.f_setLine();
      }
      return;
    }
  } else if (type == "NAME") {
    if (nameVal == "") {
      if (disGubun == 2) {
        scwin.f_setLine();
      }
      return;
    }
  }
  if (type == "CODE") {
    scwin.f_openCommonPopUp(disGubun, codeVal, "", "T", "T");
  } else if (type == "NAME") {
    scwin.f_openCommonPopUp(disGubun, "", nameVal, "T", "T");
  } else {
    scwin.f_openCommonPopUp(disGubun, codeVal, nameVal, "F", "F");
  }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  // 선언부
  var rtnList = new Array(); // 공통POP-UP -> 요청화면 

  switch (disGubun) {
    case 1:
      // CY 팝업
      udc_wrkPlCd.setSelectId('retrieveWrkPlInfo');
      rtnList = udc_wrkPlCd.cfCommonPopUp(scwin.udc_wrkPlCdCallback, pCode, pName, "T", null, null, null, null, ',,,', null, null, null, null, null, pAllSearch, "CY,CY코드,CY명");
      break;
    case 2:
      // 선사 팝업
      udc_shpCo.setSelectId('retrieveClntInfo');
      rtnList = udc_shpCo.cfCommonPopUp(scwin.udc_shpCoCallback, pCode, pName, pClose, null, null, null, null, 'SHP', null, null, null, null, null, pAllSearch, "선사,선사코드,선사명");
      break;
    case 4:
      // 본선 팝업			
      udc_cvssl.setSelectId('retrieveVsslCdInfo');
      rtnList = udc_cvssl.cfCommonPopUp(scwin.udc_cvsslCallback, pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "본선,본선코드,본선명");
      break;
    case 5:
      // 화주 팝업	
      udc_mchtCd.setSelectId('retrieveClntInfo');
      rtnList = udc_mchtCd.cfCommonPopUp(scwin.udc_mchtCdCallback, pCode, pName, pClose, null, null, null, null, 'MCHT', null, null, null, null, null, pAllSearch, "화주,화주코드,화주명");
      break;
    default:
      break;
  }
};

