scwin.f_setLine = async function () {
  var strCb = "";
  ds_LineList.setJSON([]); //초기화
  if (scwin.userId == "dwstms") {
    //TMSC 라인일때 - 2017.11.23 서동원 추가 
    strCb = 'TMSC^DOOWOO SHIPPING CO.,LTD';
    scwin.f_setLineEtc(strCb);
  } else if (scwin.userId == "namdo11") {
    //BPTCY 입주 수리업체(남도) 권한 부여 2022.06.13 박태홍과장 
    strCb = 'KDM^KUKDONG MARITIME EQUIPMENT SERVICE,SWIL^The China Navigation Co. Pte. Ltd.';
    scwin.f_setLineEtc(strCb);
  } else if (scwin.userId == "dygamman") {
    //BPTCY 입주 수리업체(대양) 권한 부여 2022.06.13 박태홍과장 
    strCb = 'BAL^BAL KOREA,HLT^BAL KOREA,MWL^MUWOON,PKE^PANTOS,SWIL^The China Navigation Co. Pte. Ltd.,TCA^TRANS CONTAINER LINE';
    scwin.f_setLineEtc(strCb);
  } else if (scwin.userId == "VANFIX") {
    //BPTCY 입주 수리업체(유니온) 권한 부여 2022.06.13 박태홍과장
    strCb = 'KITO^KITO LOGISTICS,KYW^KYOWA LINE,LOQD^QINGDAO LOGISTICS,MSN^MATSON NAVIGATION COMPANY, INC,SHDO^SHANDONG D&T SHIPPING CO.LTD,TAT^QINGDAO TALENT,TOP^TOPOCEAN INTL,UFR^UNION FORTUNE,WSC^WOSCO LINE';
    scwin.f_setLineEtc(strCb);
  } else {
    const jsonData = {
      sysCd: "LineEBC" // 시스템코드
      ,

      queryId: "retrieveLineEachShpCoCdCombo" // 쿼리ID
      ,

      param1: scwin.loginClntNo,
      param2: scwin.userClsCd,
      param3: ed_shpCo.getValue()
    };
    ds_condition_combo.setJSON(jsonData);
    await $c.sbm.execute($p, sbm_line);
  }
};
scwin.f_setLineEtc = function (strCb) {
  var arr = strCb.split(",");
  //console.log(arrLine);
  for (var i = 0; i < arr.length; i++) {
    var arrLine = arr[i].split("^");
    var code = arrLine[0];
    var name = arrLine[1];
    ds_LineList.insertRow(i);
    ds_LineList.setCellData(i, "code", code);
    ds_LineList.setCellData(i, "name", name);
  }
};

