scwin.gr_excel_onfilereadend = async function (value) {
  //console.log('scwin.gr_excel_onfilereadend1');

  if (ds_excel.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
    return false;
  } else {
    //ds_retrieve.setJSON(ds_excel.getAllJSON());

    var row = 0;
    for (var i = 0; i < ds_excel.getRowCount(); i++) {
      if (ds_excel.getCellData(i, "currPosCd") != "") {
        row = ds_retrieve.insertRow();
        //ds_retrieve.setCellData(row, "cntrNo", ds_excel.getCellData(i, "cntrNo"));
        //ds_retrieve.setCellData(row, "shedPos", ds_excel.getCellData(i, "shedPos"));

        ds_retrieve.setCellData(row, "cntrNo", ds_excel.getCellData(i, "currPosCd"));
        ds_retrieve.setCellData(row, "shedPos", ds_excel.getCellData(i, "lineCd"));
      }
    }
    gr_ContainerYardEachStockPresentConditionInformation.setRowStatusVisible(true);
    tbx_totalRows.setValue(ds_retrieve.getRowCount());
    ds_excel.setJSON([]);
  }
};

