scwin.sbm_retrieve_submitdone = async function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
  var rowcnt = ds_retrieve.getRowCount();
  tbx_totalRows.setValue(rowcnt);
  if (rowcnt == 0) {
    await $c.win.alert($p, "조회된 데이터가 없습니다.");
    return;
  }
  var options = {};
  options.sortIndex = "currPosCd lineCd impExpClsCd";
  options.sortOrder = "1 1 1";
  ds_retrieve.multisort(options);
  gr_ContainerYardEachStockPresentConditionInformation.setFocusedCell(0, "currPosCd", false);
  gr_ContainerYardEachStockPresentConditionInformation.setRowStatusVisible(false);
  //gr_ContainerYardEachStockPresentConditionInformation.setRowStatusColumnWidth(50);
};
