scwin.f_getSubtotalText1 = function (data) {
  let ret = data.split("|");
  return ret[0];
};
scwin.f_getSubtotalText2 = function (data) {
  let ret = data.split("|");
  var jsonData = ds_LkStepNo3.getMatchedJSON('code', ret[1]);
  var retData = jsonData.length > 0 ? jsonData[0].name : "";
  return retData;
};
scwin.f_getSubtotalText3 = function (data) {
  let ret = data.split("|");
  let val = "";
  if (ret[3] == "1") {
    val = "Y";
  } else if (ret[5] == "0") {
    val = "N";
  }
  return val;
};
scwin.f_getSubtotalText4 = function (data) {
  let ret = data.split("|");
  let val = "";
  if (ret[4] == "1") {
    val = "예정";
  } else if (ret[5] == "0") {
    val = "완료";
  }
  return val;
};
scwin.f_getSubtotalText5 = function (data) {
  let ret = data.split("|");
  let val = "";
  if (ret[5] == "1") {
    val = "Y";
  } else if (ret[5] == "0") {
    val = "N";
  }
  return val;
};
scwin.upperCase = function (e) {
  var obj = window[e.target.id];
  if (obj && obj.getValue) {
    var oldValue = obj._oldValue;
    var upperVal = obj.getValue().toUpperCase();
    obj.setValue(upperVal);
    obj._oldValue = oldValue;
  }
};
